"use strict";parserFactory.register("anythingnovel.com",()=>new AnythingNovelParser);class AnythingNovelParser extends Parser{constructor(){super()}getChapterUrls(e){let t=[...e.querySelectorAll("div#content li a")].reverse().map(e=>util.hyperLinkToChapter(e));return Promise.resolve(t)}findContent(e){return e.querySelector("div#content")}extractTitleImpl(e){return e.querySelector("div#content h1")}removeUnwantedElementsFromContentElement(e){super.removeUnwantedElementsFromContentElement(e),util.removeElements(e.querySelectorAll("div.ads, div#pagination, div.sharebar")),this.removeShareThisChapterLink(e)}removeShareThisChapterLink(e){let t=e.querySelector("a h2");null!=t&&t.parentElement.remove()}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#content div:not(.clearfix)")]}cleanInformationNode(e){let t=[...e.querySelectorAll("img")].map(e=>e.parentElement);util.removeElements(t)}}